INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Rowing_Stationary','Rowing, Stationary','cuádriceps',ARRAY['bíceps','pantorrillas','glúteos','isquiotibiales','espalda baja','espalda media'],'máquina','cardio',ARRAY['To begin, seat yourself on the rower. Make sure that your heels are resting comfortably against the base of the foot pedals and that the straps are secured. Select the program that you wish to use, if applicable. Sit up straight and bend forward at the hips.','There are three phases of movement when using a rower. The first phase is when you come forward on the rower. Your knees are bent and against your chest. Your upper body is leaning slightly forward while still maintaining good posture. Next, push against the foot pedals and extend your legs while bringing your hands to your upper abdominal area, squeezing your shoulders back as you do so. To avoid straining your back, use primarily your leg and hip muscles.','The recovery phase simply involves straightening your arms, bending the knees, and bringing your body forward again as you transition back into the first phase.'],'To begin, seat yourself on the rower. Make sure that your heels are resting comfortably against the base of the foot pedals and that the straps are secured. Select the program that you wish to use, if applicable. Sit up straight and bend forward at the hips. There are three phases of movement when using a rower. The first phase is when you come forward on the rower. Your knees are bent and against your chest. Your upper body is leaning slightly forward while still maintaining good posture. Next, push against the foot pedals and extend your legs while bringing your hands to your upper abdominal area, squeezing your shoulders back as you do so. To avoid straining your back, use primarily your leg and hip muscles. The recovery phase simply involves straightening your arms, bending the knees, and bringing your body forward again as you transition back into the first phase.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rowing_Stationary/0.jpg','exercisedb',true),('Runners_Stretch','Runner''s Stretch','isquiotibiales',ARRAY['pantorrillas'],NULL,'stretching',ARRAY['It''''s easiest to get into this stretch if you start standing up, put one leg behind you, and slowly lower your torso down to the floor.','Keep the front heel on the floor (if it lifts up, scoot your other leg further back).','Place your hands on either side of your front leg. To get more out of this stretch, push your butt up toward the ceiling, and then gradually lower it back toward the floor. You''''ll Stretch the hip flexor of the back leg and the hamstring and buttocks of the front.'],'It''s easiest to get into this stretch if you start standing up, put one leg behind you, and slowly lower your torso down to the floor. Keep the front heel on the floor (if it lifts up, scoot your other leg further back). Place your hands on either side of your front leg. To get more out of this stretch, push your butt up toward the ceiling, and then gradually lower it back toward the floor. You''ll Stretch the hip flexor of the back leg and the hamstring and buttocks of the front.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Runners_Stretch/0.jpg','exercisedb',true),('Running_Treadmill','Running, Treadmill','cuádriceps',ARRAY['pantorrillas','glúteos','isquiotibiales'],'máquina','cardio',ARRAY['To begin, step onto the treadmill and select the desired option from the menu. Most treadmills have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout.','Treadmills offer convenience, cardiovascular benefits, and usually have less impact than running outside. A 150 lb person will burn over 450 calories running 8 miles per hour for 30 minutes. Maintain proper posture as you run, and only hold onto the handles when necessary, such as when dismounting or checking your heart rate.'],'To begin, step onto the treadmill and select the desired option from the menu. Most treadmills have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout. Treadmills offer convenience, cardiovascular benefits, and usually have less impact than running outside. A 150 lb person will burn over 450 calories running 8 miles per hour for 30 minutes. Maintain proper posture as you run, and only hold onto the handles when necessary, such as when dismounting or checking your heart rate.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Running_Treadmill/0.jpg','exercisedb',true),('Russian_Twist','Russian Twist','abdominales',ARRAY['espalda baja'],'peso corporal','strength',ARRAY['Lie down on the floor placing your feet either under something that will not move or by having a partner hold them. Your legs should be bent at the knees.','Elevate your upper body so that it creates an imaginary V-shape with your thighs. Your arms should be fully extended in front of you perpendicular to your torso and with the hands clasped. This is the starting position.','Twist your torso to the right side until your arms are parallel with the floor while breathing out.','Hold the contraction for a second and move back to the starting position while breathing out. Now move to the opposite side performing the same techniques you applied to the right side.','Repeat for the recommended amount of repetitions.'],'Lie down on the floor placing your feet either under something that will not move or by having a partner hold them. Your legs should be bent at the knees. Elevate your upper body so that it creates an imaginary V-shape with your thighs. Your arms should be fully extended in front of you perpendicular to your torso and with the hands clasped. This is the starting position. Twist your torso to the right side until your arms are parallel with the floor while breathing out. Hold the contraction for a second and move back to the starting position while breathing out. Now move to the opposite side performing the same techniques you applied to the right side. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Russian_Twist/0.jpg','exercisedb',true),('Sandbag_Load','Sandbag Load','cuádriceps',ARRAY['abdominales','bíceps','pantorrillas','antebrazos','glúteos','isquiotibiales','espalda baja','espalda media','hombros','trapecios'],'otro','strongman',ARRAY['To load sandbags or other objects, begin with the implements placed a distance from the loading platform, typically 50 feet.','Begin by lifting the sandbag. Sandbags are extremely awkward, and the manner of lifting them can vary depending on the particular sandbag used. Reach as far around it as possible, extending through the hips and knees to pull it up high. Shouldering is usually not allowed.','Move as quickly as possible to the platform, and load it, extending through your hips, knees, and ankles to get it as high as possible. Place it onto the platform, ensuring it doesn''''t fall off.','Return to the starting position to retrieve the next sandbag, and repeat until the event is completed.'],'To load sandbags or other objects, begin with the implements placed a distance from the loading platform, typically 50 feet. Begin by lifting the sandbag. Sandbags are extremely awkward, and the manner of lifting them can vary depending on the particular sandbag used. Reach as far around it as possible, extending through the hips and knees to pull it up high. Shouldering is usually not allowed. Move as quickly as possible to the platform, and load it, extending through your hips, knees, and ankles to get it as high as possible. Place it onto the platform, ensuring it doesn''t fall off. Return to the starting position to retrieve the next sandbag, and repeat until the event is completed.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sandbag_Load/0.jpg','exercisedb',true),('Scapular_Pull-Up','Scapular Pull-Up','trapecios',ARRAY['dorsales','espalda media'],NULL,'strength',ARRAY['Take a pronated grip on a pull-up bar.','From a hanging position, raise yourself a few inches without using your arms. Do this by depressing your shoulder girdle in a reverse shrugging motion.','Pause at the completion of the movement, and then slowly return to the starting position before performing more repetitions.'],'Take a pronated grip on a pull-up bar. From a hanging position, raise yourself a few inches without using your arms. Do this by depressing your shoulder girdle in a reverse shrugging motion. Pause at the completion of the movement, and then slowly return to the starting position before performing more repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Scapular_Pull-Up/0.jpg','exercisedb',true),('Scissor_Kick','Scissor Kick','abdominales',ARRAY[]::text[],'peso corporal','stretching',ARRAY['To begin, lie down with your back pressed against the floor or on an exercise mat (optional). Your arms should be fully extended to the sides with your palms facing down. Note: The arms should be stationary the entire time.','With a slight bend at the knees, lift your legs up so that your heels are about 6 inches off the ground. This is the starting position.','Now lift your left leg up to about a 45 degree angle while your right leg is lowered until the heel is about 2-3 inches from the ground.','Switch movements by raising your right leg up and lowering your left leg. Remember to breathe while performing this exercise.','Repeat for the recommended amount of repetitions.'],'To begin, lie down with your back pressed against the floor or on an exercise mat (optional). Your arms should be fully extended to the sides with your palms facing down. Note: The arms should be stationary the entire time. With a slight bend at the knees, lift your legs up so that your heels are about 6 inches off the ground. This is the starting position. Now lift your left leg up to about a 45 degree angle while your right leg is lowered until the heel is about 2-3 inches from the ground. Switch movements by raising your right leg up and lowering your left leg. Remember to breathe while performing this exercise. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Scissor_Kick/0.jpg','exercisedb',true),('Scissors_Jump','Scissors Jump','cuádriceps',ARRAY['glúteos','isquiotibiales'],'peso corporal','plyometrics',ARRAY['Assume a lunge stance position with one foot forward with the knee bent, and the rear knee nearly touching the ground.','Ensure that the front knee is over the midline of the foot. Extending through both legs, jump as high as possible, swinging your arms to gain lift.','As you jump as high as you can, switch the position of your legs, moving your front leg to the back and the rear leg to the front.','As you land, absorb the impact through the legs by adopting the lunge position, and repeat.'],'Assume a lunge stance position with one foot forward with the knee bent, and the rear knee nearly touching the ground. Ensure that the front knee is over the midline of the foot. Extending through both legs, jump as high as possible, swinging your arms to gain lift. As you jump as high as you can, switch the position of your legs, moving your front leg to the back and the rear leg to the front. As you land, absorb the impact through the legs by adopting the lunge position, and repeat.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Scissors_Jump/0.jpg','exercisedb',true),('Seated_Band_Hamstring_Curl','Seated Band Hamstring Curl','isquiotibiales',ARRAY[]::text[],'otro','strength',ARRAY['Secure a band close to the ground and place a bench a couple feet away from it.','Seat yourself on the bench and secure the band behind your ankles, beginning with your legs straight. This will be your starting position.','Flex the knees, bringing your feet towards the bench. You may need to lean back slightly to keep your feet from striking the floor.','Pause at the completion of the movement, and then slowly return to the starting position.'],'Secure a band close to the ground and place a bench a couple feet away from it. Seat yourself on the bench and secure the band behind your ankles, beginning with your legs straight. This will be your starting position. Flex the knees, bringing your feet towards the bench. You may need to lean back slightly to keep your feet from striking the floor. Pause at the completion of the movement, and then slowly return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Band_Hamstring_Curl/0.jpg','exercisedb',true),('Seated_Barbell_Military_Press','Seated Barbell Military Press','hombros',ARRAY['tríceps'],'barra','strength',ARRAY['Sit on a Military Press Bench with a bar behind your head and either have a spotter give you the bar (better on the rotator cuff this way) or pick it up yourself carefully with a pronated grip (palms facing forward). Tip: Your grip should be wider than shoulder width and it should create a 90-degree angle between the forearm and the upper arm as the barbell goes down.','Once you pick up the barbell with the correct grip length, lift the bar up over your head by locking your arms. Hold at about shoulder level and slightly in front of your head. This is your starting position.','Lower the bar down to the collarbone slowly as you inhale.','Lift the bar back up to the starting position as you exhale.','Repeat for the recommended amount of repetitions.'],'Sit on a Military Press Bench with a bar behind your head and either have a spotter give you the bar (better on the rotator cuff this way) or pick it up yourself carefully with a pronated grip (palms facing forward). Tip: Your grip should be wider than shoulder width and it should create a 90-degree angle between the forearm and the upper arm as the barbell goes down. Once you pick up the barbell with the correct grip length, lift the bar up over your head by locking your arms. Hold at about shoulder level and slightly in front of your head. This is your starting position. Lower the bar down to the collarbone slowly as you inhale. Lift the bar back up to the starting position as you exhale. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Barbell_Military_Press/0.jpg','exercisedb',true);